module median_filter (
    input [7:0] sample0,
    input [7:0] sample1,
    input [7:0] sample2,
    input [7:0] sample3,
    input [7:0] sample4,
    output reg [7:0] median
);
    reg [7:0] unused_samples [0:4];
    integer i, j;

    always @(*) begin
        // Store the unused_samples in an array
        unused_samples[0] = sample0;
        unused_samples[1] = sample1;
        unused_samples[2] = sample2;
        unused_samples[3] = sample3;
        unused_samples[4] = sample4;

        // Simple bubble sort to sort the unused_samples
        for (i = 0; i < 4; i = i + 1) begin
            for (j = 0; j < 4 - i; j = j + 1) begin
                if (unused_samples[j] > unused_samples[j + 1]) begin
                    // Swap
                    {unused_samples[j], unused_samples[j + 1]} = {unused_samples[j + 1], unused_samples[j]};
                end
            end
        end

        // Median is the middle element (third one in sorted order)
        median = unused_samples[2];
    end
endmodule
